/* ═══════════════════════════════════════════════════
   ⑤ PROCESS — sticky horizontal stepper
      Scrolling advances through steps visually
═══════════════════════════════════════════════════ */
function ProcessSection() {
  const wrapRef = useRef(null);
  const prog    = useElProgress(wrapRef);
  const activeIdx = Math.min(PROCESS.length - 1, Math.floor(prog * PROCESS.length));
  const subProg   = (prog * PROCESS.length) % 1; // 0→1 within each step

  return (
    <div ref={wrapRef} id="sec-process" style={{ height: `${100 + PROCESS.length * 80}vh`, position: 'relative' }}>
      <div style={{ position: 'sticky', top: 0, height: '100vh', overflow: 'hidden', display: 'flex', background: '#f4f6fb' }}>

        {/* Left — step list */}
        <div style={{ width: 'clamp(240px,35%,420px)', padding: '0 0 0 clamp(20px,4vw,60px)', display: 'flex', flexDirection: 'column', justifyContent: 'center', borderRight: '1px solid var(--rule)', flexShrink: 0 }}>
          <div style={{ marginBottom: 28 }}>
            <span style={{ fontSize: '0.65rem', fontWeight: 700, letterSpacing: '0.18em', textTransform: 'uppercase', color: 'var(--ink20)', display: 'block', marginBottom: 8 }}>How We Work</span>
            <h2 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(1.6rem,3vw,2.4rem)', fontWeight: 900, color: 'var(--ink)', letterSpacing: '-0.025em', lineHeight: 1.1 }}>Our Proven Process</h2>
          </div>
          {PROCESS.map(({ n, Icon, t }, i) => (
            <div key={n} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', borderRadius: 12, marginBottom: 4, background: activeIdx === i ? 'var(--white)' : 'transparent', border: activeIdx === i ? '1px solid var(--rule)' : '1px solid transparent', boxShadow: activeIdx === i ? '0 3px 16px rgba(0,0,0,0.05)' : 'none', transform: activeIdx === i ? 'translateX(10px)' : 'translateX(0)', transition: 'all 0.5s cubic-bezier(0.16,1,0.3,1)' }}>
              <div style={{ width: 36, height: 36, borderRadius: 9, flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', background: activeIdx === i ? '#0057ff' : 'var(--rule)', color: activeIdx === i ? '#fff' : 'var(--ink40)', transition: 'all 0.4s' }}><Icon size={15} /></div>
              <div>
                <span style={{ fontSize: '0.58rem', fontWeight: 700, letterSpacing: '0.12em', textTransform: 'uppercase', color: activeIdx === i ? '#0057ff' : 'var(--ink20)', display: 'block' }}>Step {n}</span>
                <strong style={{ fontSize: '0.9rem', color: activeIdx === i ? 'var(--ink)' : 'var(--ink40)', fontWeight: 700 }}>{t}</strong>
              </div>
              {activeIdx === i && <div style={{ marginLeft: 'auto', width: 7, height: 7, borderRadius: '50%', background: '#0057ff', flexShrink: 0 }} />}
            </div>
          ))}

          {/* Vertical progress line */}
          <div style={{ position: 'absolute', left: 'clamp(20px,4vw,60px)', top: '50%', width: 2, height: `${PROCESS.length * 60}px`, transform: 'translateY(-50%)', background: 'var(--rule)', overflow: 'hidden', borderRadius: 1, display: 'none' }}>
            <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: `${prog * 100}%`, background: '#0057ff', transition: 'none' }} />
          </div>
        </div>

        {/* Right — detail card + animated fill */}
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 'clamp(28px,4vw,60px)', position: 'relative', overflow: 'hidden' }}>
          {/* Background fill that sweeps per-step */}
          <div style={{ position: 'absolute', inset: 0, background: `rgba(0,87,255,${subProg * 0.03})`, transition: 'background 0.3s ease' }} />
          <Tilt style={{ width: '100%', maxWidth: 520 }}>
            <div style={{ background: '#fff', border: '1px solid var(--rule)', borderRadius: 24, padding: 'clamp(32px,4vw,52px)', boxShadow: '0 8px 48px rgba(0,0,0,0.07)' }}>
              {(() => {
                const { n, Icon, t, d } = PROCESS[activeIdx];
                return (
                  <>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 28 }}>
                      <div style={{ width: 60, height: 60, borderRadius: 16, background: '#0057ff', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', boxShadow: '0 8px 26px rgba(0,87,255,0.35)', flexShrink: 0 }}><Icon size={26} /></div>
                      <div>
                        <span style={{ fontSize: '0.62rem', fontWeight: 700, letterSpacing: '0.16em', textTransform: 'uppercase', color: '#0057ff', display: 'block' }}>Step {n}</span>
                        <h3 style={{ fontFamily: 'var(--serif)', fontSize: 'clamp(1.5rem,3vw,2rem)', fontWeight: 900, color: 'var(--ink)', lineHeight: 1.1 }}>{t}</h3>
                      </div>
                    </div>
                    <p style={{ fontSize: '1.02rem', color: 'var(--ink60)', lineHeight: 1.92, marginBottom: 32 }}>{d}</p>
                    {/* Step fill bar */}
                    <div style={{ height: 4, background: 'var(--rule)', borderRadius: 2, overflow: 'hidden', marginBottom: 20 }}>
                      <div style={{ height: '100%', width: `${subProg * 100}%`, background: '#0057ff', borderRadius: 2, transition: 'none', boxShadow: '0 0 8px rgba(0,87,255,0.5)' }} />
                    </div>
                    {/* Dot nav */}
                    <div style={{ display: 'flex', gap: 7 }}>
                      {PROCESS.map((_, pi) => <div key={pi} style={{ height: 4, borderRadius: 2, background: pi === activeIdx ? '#0057ff' : 'var(--rule)', width: pi === activeIdx ? 32 : 8, transition: 'all 0.4s cubic-bezier(0.16,1,0.3,1)' }} />)}
                    </div>
                  </>
                );
              })()}
            </div>
          </Tilt>
        </div>
      </div>
    </div>
  );
}

